/**
 * A simple implementation of a MinHeap tailored for Dijkstra's algorithm.
 * Stores [distance, node] pairs, prioritizing smaller distances.
 */
class MinPriorityQueue {
    constructor() {
        // Heap stores elements as [distance, node]
        this.heap = [];
    }

    isEmpty() {
        return this.heap.length === 0;
    }

    size() {
        return this.heap.length;
    }

    _parent(i) {
        return Math.floor((i - 1) / 2);
    }

    _left(i) {
        return 2 * i + 1;
    }

    _right(i) {
        return 2 * i + 2;
    }

    _swap(i, j) {
        [this.heap[i], this.heap[j]] = [this.heap[j], this.heap[i]];
    }

    _bubbleUp(index) {
        let currentIndex = index;
        while (currentIndex > 0) {
            const parentIndex = this._parent(currentIndex);
            // Compare distances (the 0th element)
            if (this.heap[currentIndex][0] < this.heap[parentIndex][0]) {
                this._swap(currentIndex, parentIndex);
                currentIndex = parentIndex;
            } else {
                break;
            }
        }
    }

    _bubbleDown(index) {
        let currentIndex = index;
        const lastIndex = this.heap.length - 1;

        while (true) {
            let left = this._left(currentIndex);
            let right = this._right(currentIndex);
            let smallest = currentIndex;

            // Compare distances
            if (left <= lastIndex && this.heap[left][0] < this.heap[smallest][0]) {
                smallest = left;
            }
            if (right <= lastIndex && this.heap[right][0] < this.heap[smallest][0]) {
                smallest = right;
            }

            if (smallest !== currentIndex) {
                this._swap(currentIndex, smallest);
                currentIndex = smallest;
            } else {
                break;
            }
        }
    }

    push(element) {
        this.heap.push(element);
        this._bubbleUp(this.heap.length - 1);
    }

    pop() {
        if (this.isEmpty()) return null;
        if (this.heap.length === 1) return this.heap.pop();

        const root = this.heap[0];
        this.heap[0] = this.heap.pop();
        this._bubbleDown(0);
        return root;
    }
}


function solve(n, prices, roads) {
    const INF = Number.POSITIVE_INFINITY;

    // 1. Build adjacency lists for Empty and Carrying travel
    const adjEmpty = Array(n).fill(0).map(() => []);
    const adjCarrying = Array(n).fill(0).map(() => []);

    for (const [u, v, cost, tax] of roads) {
        // Empty travel (Cost = C)
        adjEmpty[u].push({ node: v, weight: cost });
        adjEmpty[v].push({ node: u, weight: cost });

        // Carrying travel (Cost = C * T)
        const carryingCost = cost * tax;
        adjCarrying[u].push({ node: v, weight: carryingCost });
        adjCarrying[v].push({ node: u, weight: carryingCost });
    }

    /**
     * Dijkstra's algorithm to find shortest paths from a starting node.
     * @param {number} startNode - The node to start from.
     * @param {Array<Array<{node: number, weight: number}>>} adj - The adjacency list.
     * @returns {number[]} An array where result[i] is the shortest distance from startNode to i.
     */
    const dijkstra = (startNode, adj) => {
        const distances = Array(n).fill(INF);
        distances[startNode] = 0;

        const pq = new MinPriorityQueue();
        // Store [distance, node]
        pq.push([0, startNode]);

        while (!pq.isEmpty()) {
            const [d, u] = pq.pop();

            if (d > distances[u]) {
                continue;
            }

            for (const edge of adj[u]) {
                const v = edge.node;
                const weight = edge.weight;

                const newDist = distances[u] + weight;

                if (newDist < distances[v]) {
                    distances[v] = newDist;
                    pq.push([newDist, v]);
                }
            }
        }
        return distances;
    };

    // 2. Calculate All-Pairs Shortest Paths (APSP)

    // DistEmpty[i][j]: Shortest path i -> j empty-handed
    const DistEmpty = Array(n).fill(0).map(() => []);
    for (let i = 0; i < n; i++) {
        DistEmpty[i] = dijkstra(i, adjEmpty);
    }

    // DistCarrying[i][j]: Shortest path i -> j carrying apples
    const DistCarrying = Array(n).fill(0).map(() => []);
    for (let i = 0; i < n; i++) {
        DistCarrying[i] = dijkstra(i, adjCarrying);
    }

    // 3. Determine the minimum cost for each store i
    const ans = [];

    for (let i = 0; i < n; i++) {
        // Option 1: Buy directly at i
        let minCost = prices[i];

        // Option 2: Travel from i to j, buy at j, return from j to i
        for (let j = 0; j < n; j++) {
            // Cost = D_empty(i, j) + prices[j] + D_carrying(j, i)

            const costToJ = DistEmpty[i][j];
            const costFromJ = DistCarrying[j][i];

            // Only consider valid paths
            if (costToJ !== INF && costFromJ !== INF) {
                // Note: If j=i, costToJ=0, costFromJ=0, cost = prices[i], which is handled by initialization.
                const totalCost = costToJ + prices[j] + costFromJ;
                if (totalCost < minCost) {
                    minCost = totalCost;
                }
            }
        }
        ans.push(minCost);
    }

    return ans;
}

