    const adjCarrying = Array(n).fill(0).map(() => []);

    for (const [u, v, cost, tax] of roads) {
        // Empty travel (Cost = C)
        adjEmpty[u].push({ node: v, weight: cost });
        adjEmpty[v].push({ node: u, weight: cost });

        // Carrying travel (Cost = C * T)
        const carryingCost = cost * tax;
        adjCarrying[u].push({ node: v, weight: carryingCost });
        adjCarrying[v].push({ node: u, weight: carryingCost });
    }

    /**
     * Dijkstra's algorithm to find shortest paths from a starting node.
     * @param {number} startNode - The node to start from.
     * @param {Array<Array<{node: number, weight: number}>>} adj - The adjacency list.
     * @returns {number[]} An array where result[i] is the shortest distance from startNode to i.
     */
    const dijkstra = (startNode, adj) => {
        const distances = Array(n).fill(INF);
        distances[startNode] = 0;

        const pq = new MinPriorityQueue();
        // Store [distance, node]
        pq.push([0, startNode]);

        while (!pq.isEmpty()) {
            const [d, u] = pq.pop();

            if (d > distances[u]) {
                continue;
            }

            for (const edge of adj[u]) {
                const v = edge.node;
                const weight = edge.weight;

                const newDist = distances[u] + weight;

                if (newDist < distances[v]) {
                    distances[v] = newDist;
                    pq.push([newDist, v]);
                }
            }
        }
        return distances;
    };

    // 2. Calculate All-Pairs Shortest Paths (APSP)

    // DistEmpty[i][j]: Shortest path i -> j empty-handed
    const DistEmpty = Array(n).fill(0).map(() => []);
    for (let i = 0; i < n; i++) {
        DistEmpty[i] = dijkstra(i, adjEmpty);
    }

    // DistCarrying[i][j]: Shortest path i -> j carrying apples
    const DistCarrying = Array(n).fill(0).map(() => []);
    for (let i = 0; i < n; i++) {
        DistCarrying[i] = dijkstra(i, adjCarrying);
    }

    // 3. Determine the minimum cost for each store i
    const ans = [];

    for (let i = 0; i < n; i++) {
        // Option 1: Buy directly at i
        let minCost = prices[i];

        // Option 2: Travel from i to j, buy at j, return from j to i
        for (let j = 0; j < n; j++) {
