class MinPriorityQueue {
    constructor() {
        // Heap stores elements as [distance, node]
        this.heap = [];
    }

    isEmpty() {
        return this.heap.length === 0;
    }

    size() {
        return this.heap.length;
    }

    _parent(i) {
        return Math.floor((i - 1) / 2);
    }

    _left(i) {
        return 2 * i + 1;
    }

    _right(i) {
        return 2 * i + 2;
    }

    _swap(i, j) {
        [this.heap[i], this.heap[j]] = [this.heap[j], this.heap[i]];
    }

    _bubbleUp(index) {
        let currentIndex = index;
        while (currentIndex > 0) {
            const parentIndex = this._parent(currentIndex);
            // Compare distances (the 0th element)
            if (this.heap[currentIndex][0] < this.heap[parentIndex][0]) {
                this._swap(currentIndex, parentIndex);
                currentIndex = parentIndex;
            } else {
                break;
            }
        }
    }

    _bubbleDown(index) {
        let currentIndex = index;
        const lastIndex = this.heap.length - 1;

        while (true) {
            let left = this._left(currentIndex);
            let right = this._right(currentIndex);
            let smallest = currentIndex;

            // Compare distances
            if (left <= lastIndex && this.heap[left][0] < this.heap[smallest][0]) {
                smallest = left;
            }
            if (right <= lastIndex && this.heap[right][0] < this.heap[smallest][0]) {
                smallest = right;
            }

            if (smallest !== currentIndex) {
                this._swap(currentIndex, smallest);
                currentIndex = smallest;
            } else {
                break;
            }
        }
    }

    push(element) {
        this.heap.push(element);
        this._bubbleUp(this.heap.length - 1);
    }

    pop() {
        if (this.isEmpty()) return null;
        if (this.heap.length === 1) return this.heap.pop();

        const root = this.heap[0];
        this.heap[0] = this.heap.pop();
        this._bubbleDown(0);
        return root;
    }
}


